graphql.query:
query GetShopInfo {
  shop {
    name
    description
    primaryDomain { url host }
    paymentSettings {
      currencyCode
      acceptedCardBrands
      enabledPresentmentCurrencies
    }
  }
}

query GetProducts($first: Int!, $after: String) {
  products(first: $first, after: $after) {
    edges {
      cursor
      node {
        id
        title
        description
        vendor
        productType
        tags
        availableForSale
        priceRange {
          minVariantPrice { amount currencyCode }
          maxVariantPrice { amount currencyCode }
        }
        compareAtPriceRange {
          minVariantPrice { amount currencyCode }
        }
        images(first: 5) {
          edges { node { id url altText width height } }
        }
        variants(first: 10) {
          edges {
            node {
              id
              title
              availableForSale
              quantityAvailable
              price { amount currencyCode }
              compareAtPrice { amount currencyCode }
              selectedOptions { name value }
              image { url altText }
            }
          }
        }
      }
    }
    pageInfo { hasNextPage hasPreviousPage endCursor startCursor }
  }
}

query GetProduct($id: ID!) {
  product(id: $id) {
    id
    title
    description
    descriptionHtml
    vendor
    productType
    tags
    availableForSale
    priceRange {
      minVariantPrice { amount currencyCode }
      maxVariantPrice { amount currencyCode }
    }
    compareAtPriceRange {
      minVariantPrice { amount currencyCode }
    }
    images(first: 20) {
      edges { node { id url altText width height } }
    }
    options {
      id
      name
      values
    }
    variants(first: 30) {
      edges {
        node {
          id
          title
          availableForSale
          quantityAvailable
          price { amount currencyCode }
          compareAtPrice { amount currencyCode }
          selectedOptions { name value }
          image { url altText }
        }
      }
    }
    metafields(identifiers: [
      { namespace: "reviews", key: "rating" },
      { namespace: "reviews", key: "rating_count" }
    ]) {
      key
      namespace
      value
      type
    }
  }
}

query GetProductByHandle($handle: String!) {
  productByHandle(handle: $handle) {
    id
    title
    description
    vendor
    availableForSale
    priceRange {
      minVariantPrice { amount currencyCode }
    }
    images(first: 10) {
      edges { node { url altText } }
    }
    options { id name values }
    variants(first: 30) {
      edges {
        node {
          id
          title
          availableForSale
          quantityAvailable
          price { amount currencyCode }
          selectedOptions { name value }
        }
      }
    }
  }
}

query GetProductsByVendor($query: String!, $first: Int!, $after: String) {
  products(first: $first, after: $after, query: $query) {
    edges {
      cursor
      node {
        id
        title
        vendor
        availableForSale
        priceRange {
          minVariantPrice { amount currencyCode }
        }
        images(first: 1) {
          edges { node { url altText } }
        }
        variants(first: 5) {
          edges {
            node { id title availableForSale quantityAvailable price { amount currencyCode } }
          }
        }
      }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query GetProductsByPriceAsc($first: Int!, $after: String) {
  products(first: $first, after: $after, sortKey: PRICE, reverse: false) {
    edges {
      cursor
      node {
        id
        title
        vendor
        availableForSale
        priceRange {
          minVariantPrice { amount currencyCode }
        }
        images(first: 1) {
          edges { node { url altText } }
        }
      }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query GetBestSellingProducts($first: Int!, $after: String) {
  products(first: $first, after: $after, sortKey: BEST_SELLING) {
    edges {
      cursor
      node {
        id
        title
        vendor
        availableForSale
        priceRange {
          minVariantPrice { amount currencyCode }
        }
        images(first: 1) {
          edges { node { url altText } }
        }
      }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query GetProductRecommendations($productId: ID!) {
  productRecommendations(productId: $productId) {
    id
    title
    vendor
    availableForSale
    priceRange {
      minVariantPrice { amount currencyCode }
    }
    images(first: 1) {
      edges { node { url altText } }
    }
  }
}

query SearchProducts($query: String!, $first: Int!, $after: String) {
  search(query: $query, first: $first, after: $after, types: [PRODUCT]) {
    totalCount
    edges {
      cursor
      node {
        ... on Product {
          id
          title
          vendor
          availableForSale
          priceRange {
            minVariantPrice { amount currencyCode }
          }
          images(first: 1) {
            edges { node { url altText } }
          }
          variants(first: 5) {
            edges {
              node { id title availableForSale quantityAvailable price { amount currencyCode } }
            }
          }
        }
      }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query PredictiveSearch($query: String!) {
  predictiveSearch(query: $query, types: [PRODUCT, COLLECTION]) {
    products {
      id
      title
      vendor
      priceRange {
        minVariantPrice { amount currencyCode }
      }
      images(first: 1) {
        edges { node { url altText } }
      }
    }
    collections {
      id
      title
      handle
      image { url altText }
    }
  }
}

query GetCollections($first: Int!, $after: String) {
  collections(first: $first, after: $after) {
    edges {
      node {
        id
        title
        handle
        description
        image { url altText }
        products(first: 1) {
          edges { node { id } }
        }
      }
    }
    pageInfo { hasNextPage endCursor }
  }
}

query GetProductsByCollection($id: ID!, $first: Int!, $after: String, $sortKey: ProductCollectionSortKeys, $reverse: Boolean) {
  collection(id: $id) {
    id
    title
    description
    image { url altText }
    products(first: $first, after: $after, sortKey: $sortKey, reverse: $reverse) {
      edges {
        cursor
        node {
          id
          title
          vendor
          availableForSale
          priceRange {
            minVariantPrice { amount currencyCode }
          }
          images(first: 1) {
            edges { node { url altText } }
          }
          variants(first: 5) {
            edges {
              node { id title availableForSale quantityAvailable price { amount currencyCode } }
            }
          }
        }
      }
      pageInfo { hasNextPage endCursor }
    }
  }
}

query GetCollectionByHandle($handle: String!, $first: Int!) {
  collectionByHandle(handle: $handle) {
    id
    title
    description
    image { url altText }
    products(first: $first) {
      edges {
        node {
          id
          title
          vendor
          availableForSale
          priceRange {
            minVariantPrice { amount currencyCode }
          }
          images(first: 1) {
            edges { node { url altText } }
          }
        }
      }
      pageInfo { hasNextPage endCursor }
    }
  }
}

mutation RegisterCustomer($input: CustomerCreateInput!) {
  customerCreate(input: $input) {
    customer {
      id
      firstName
      lastName
      email
    }
    customerUserErrors { code field message }
  }
}

mutation LoginCustomer($input: CustomerAccessTokenCreateInput!) {
  customerAccessTokenCreate(input: $input) {
    customerAccessToken {
      accessToken
      expiresAt
    }
    customerUserErrors { code field message }
  }
}

mutation LogoutCustomer($customerAccessToken: String!) {
  customerAccessTokenDelete(customerAccessToken: $customerAccessToken) {
    deletedAccessToken
    deletedCustomerAccessTokenId
    userErrors { field message }
  }
}

query GetCustomer($customerAccessToken: String!) {
  customer(customerAccessToken: $customerAccessToken) {
    id
    firstName
    lastName
    email
    phone
    createdAt
    defaultAddress {
      id firstName lastName address1 address2 city country phone zip
    }
    addresses(first: 10) {
      edges {
        node {
          id
          firstName
          lastName
          address1
          address2
          city
          province
          country
          zip
          phone
        }
      }
    }
    orders(first: 10, sortKey: PROCESSED_AT, reverse: true) {
      edges {
        node {
          id
          orderNumber
          processedAt
          financialStatus
          fulfillmentStatus
          currentTotalPrice { amount currencyCode }
          lineItems(first: 5) {
            edges {
              node {
                title
                quantity
                originalTotalPrice { amount currencyCode }
                variant { id title image { url } }
              }
            }
          }
        }
      }
    }
  }
}

mutation UpdateCustomer($customerAccessToken: String!, $customer: CustomerUpdateInput!) {
  customerUpdate(customerAccessToken: $customerAccessToken, customer: $customer) {
    customer {
      id
      firstName
      lastName
      email
      phone
    }
    customerAccessToken {
      accessToken
      expiresAt
    }
    customerUserErrors { code field message }
  }
}

mutation RecoverPassword($email: String!) {
  customerRecover(email: $email) {
    customerUserErrors { code field message }
  }
}

mutation AddCustomerAddress($customerAccessToken: String!, $address: MailingAddressInput!) {
  customerAddressCreate(customerAccessToken: $customerAccessToken, address: $address) {
    customerAddress {
      id
      firstName
      lastName
      address1
      address2
      city
      country
      zip
      phone
    }
    customerUserErrors { code field message }
  }
}

mutation UpdateCustomerAddress($customerAccessToken: String!, $id: ID!, $address: MailingAddressInput!) {
  customerAddressUpdate(customerAccessToken: $customerAccessToken, id: $id, address: $address) {
    customerAddress {
      id
      address1
      city
      country
      phone
    }
    customerUserErrors { code field message }
  }
}

mutation DeleteCustomerAddress($customerAccessToken: String!, $id: ID!) {
  customerAddressDelete(customerAccessToken: $customerAccessToken, id: $id) {
    deletedCustomerAddressId
    customerUserErrors { code field message }
  }
}

mutation SetDefaultAddress($customerAccessToken: String!, $addressId: ID!) {
  customerDefaultAddressUpdate(customerAccessToken: $customerAccessToken, addressId: $addressId) {
    customer {
      id
      defaultAddress { id address1 city country }
    }
    customerUserErrors { code field message }
  }
}

mutation CreateCart($input: CartInput!) {
  cartCreate(input: $input) {
    cart {
      id
      checkoutUrl
      totalQuantity
      cost {
        subtotalAmount { amount currencyCode }
        totalAmount { amount currencyCode }
        totalTaxAmount { amount currencyCode }
      }
      lines(first: 20) {
        edges {
          node {
            id
            quantity
            cost {
              totalAmount { amount currencyCode }
            }
            merchandise {
              ... on ProductVariant {
                id
                title
                price { amount currencyCode }
                availableForSale
                quantityAvailable
                image { url altText }
                product { id title vendor }
              }
            }
          }
        }
      }
    }
    userErrors { code field message }
  }
}

query GetCart($cartId: ID!) {
  cart(id: $cartId) {
    id
    checkoutUrl
    totalQuantity
    discountCodes { code applicable }
    cost {
      subtotalAmount { amount currencyCode }
      totalAmount { amount currencyCode }
      totalTaxAmount { amount currencyCode }
      checkoutChargeAmount { amount currencyCode }
    }
    lines(first: 20) {
      edges {
        node {
          id
          quantity
          cost {
            totalAmount { amount currencyCode }
            amountPerQuantity { amount currencyCode }
            compareAtAmountPerQuantity { amount currencyCode }
          }
          merchandise {
            ... on ProductVariant {
              id
              title
              price { amount currencyCode }
              compareAtPrice { amount currencyCode }
              availableForSale
              quantityAvailable
              selectedOptions { name value }
              image { url altText }
              product { id title vendor }
            }
          }
        }
      }
    }
  }
}

mutation AddCartLines($cartId: ID!, $lines: [CartLineInput!]!) {
  cartLinesAdd(cartId: $cartId, lines: $lines) {
    cart {
      id
      totalQuantity
      cost {
        subtotalAmount { amount currencyCode }
        totalAmount { amount currencyCode }
      }
      lines(first: 20) {
        edges {
          node {
            id
            quantity
            merchandise {
              ... on ProductVariant {
                id title price { amount currencyCode } quantityAvailable
                product { title vendor }
              }
            }
          }
        }
      }
    }
    userErrors { code field message }
  }
}

mutation UpdateCartLines($cartId: ID!, $lines: [CartLineUpdateInput!]!) {
  cartLinesUpdate(cartId: $cartId, lines: $lines) {
    cart {
      id
      totalQuantity
      cost {
        subtotalAmount { amount currencyCode }
        totalAmount { amount currencyCode }
      }
      lines(first: 20) {
        edges {
          node {
            id
            quantity
            merchandise {
              ... on ProductVariant {
                id title quantityAvailable availableForSale
              }
            }
          }
        }
      }
    }
    userErrors { code field message }
  }
}

mutation RemoveCartLines($cartId: ID!, $lineIds: [ID!]!) {
  cartLinesRemove(cartId: $cartId, lineIds: $lineIds) {
    cart {
      id
      totalQuantity
      cost {
        subtotalAmount { amount currencyCode }
        totalAmount { amount currencyCode }
      }
      lines(first: 20) {
        edges {
          node {
            id quantity
            merchandise {
              ... on ProductVariant { id title }
            }
          }
        }
      }
    }
    userErrors { code field message }
  }
}

mutation ApplyDiscountCode($cartId: ID!, $discountCodes: [String!]!) {
  cartDiscountCodesUpdate(cartId: $cartId, discountCodes: $discountCodes) {
    cart {
      id
      discountCodes { code applicable }
      cost {
        subtotalAmount { amount currencyCode }
        totalAmount { amount currencyCode }
      }
    }
    userErrors { code field message }
  }
}

query GetCustomerOrders($customerAccessToken: String!, $first: Int!, $after: String) {
  customer(customerAccessToken: $customerAccessToken) {
    id
    firstName
    orders(first: $first, after: $after, sortKey: PROCESSED_AT, reverse: true) {
      edges {
        cursor
        node {
          id
          orderNumber
          processedAt
          financialStatus
          fulfillmentStatus
          currentTotalPrice { amount currencyCode }
          currentSubtotalPrice { amount currencyCode }
          currentTotalDiscounts { amount currencyCode }
          discountApplications(first: 5) {
            edges {
              node {
                ... on DiscountCodeApplication {
                  code
                  value {
                    ... on PricingPercentageValue { percentage }
                    ... on MoneyV2 { amount currencyCode }
                  }
                }
              }
            }
          }
          lineItems(first: 10) {
            edges {
              node {
                title
                quantity
                originalTotalPrice { amount currencyCode }
                variant { id title image { url } }
              }
            }
          }
          shippingAddress {
            firstName lastName address1 city country phone
          }
        }
      }
      pageInfo { hasNextPage endCursor }
    }
  }
}
